66666_40x40.png) 50% 50% repeat;opacity:.5;filter:Alpha(Opacity=50)}.ui-widget-shadow{margin:-5px 0 0 -5px;padding:5px;background:#000 url(images/ui-bg_flat_10_000000_40x100.png) 50% 50% repeat-x;opacity:.2;filter:Alpha(Opacity=20);border-radius:5px}.link-web>a{color:#555;font-size:12px;line-height:24px}body{margin:0px; padding:3px; font-size: 20px;}*{font-size:20px !important;}.articlerelatepannel { display:none; padding: 6px;  margin-top:5px; margin-bottom:5px; background-color:#f7f7f7; border:solid 1px #0cac0c}.mediaplayercontent{display:none;}h1{font-size:24px; font-weight:bold; color:black;}h2{font-weight:bold; color:black;}h3{font-weight:bold; color:black;}iframe{display:none;}</style></head><body><div class='chitiet_tin'><h2 style=\"text-align: left;\">Mikel Arteta \u0111\u01b0\u1ee3c nh\u1eafm thay Wenger</h2>\r\n<div style=\"text-align: justify;\"><br>\r\nHLV Wenger ch\u00ednh th\u1ee9c r\u1eddi Arsenal v\u00e0o cu\u1ed1i m\u00f9a gi\u1ea3i n\u00e0y. Nhi\u1ec7m v\u1ee5 c\u1ee7a Ph\u00e1o th\u1ee7 l\u00e0 t\u00ecm ng\u01b0\u1eddi thay th\u1ebf v\u1ecb chi\u1ebfn l\u01b0\u1ee3c gia ng\u01b0\u1eddi Ph\u00e1p. Hi\u1ec7n c\u00f3 r\u1ea5t nhi\u1ec1u \u1ee9ng vi\u00ean \u0111ang l\u1ecdt v\u00e0o t\u1ea7m ng\u1eafm c\u1ee7a \u0111\u1ed9i b\u00f3ng th\u00e0nh London.</div>\r\n<div style=\"text-align: justify;\">\r\n<div style=\"text-align: center; width: 100%\" class=\"imagecontainer\">\r\n<table style=\"text-align: center; width:100%;\">\r\n    <tbody>\r\n        <tr style=\"width:100%;\">\r\n            <td style=\"width: 100%;\" align=\"center\"><img style=\"border: none\" alt=\"Aaron Ramsey phat bieu ve Mikel Arteta hinh anh\" title=\"Aaron Ramsey ph\u00e1t bi\u1ec3u v\u1ec1 Mikel Arteta h\u00ecnh \u1ea3nh\" src=\"https://static.bongda24h.vn/medias/mobile/2018/3/7/Giam-doc-dieu-hanh-Arsenal-muon-Mikel-Arteta-thay-Arsene-Wenger-hinh-anh.jpg\"></td>\r\n        </tr>\r\n        <tr>\r\n            <td>\r\n            <h3>Arteta \u0111\u01b0\u1ee3c \u0111\u1ed3n \u0111o\u00e1n thay th\u1ebf Wenger</h3>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n</div>\r\nLuis Enrique v\u00e0 Massimiliano Allegri l\u00e0 nh\u1eefng m\u1ee5c ti\u00eau h\u00e0ng \u0111\u1ea7u thay th\u1ebf Wenger, m\u1ed9t s\u1ed1 ng\u01b0\u1eddi c\u0169 c\u1ee7a Ph\u00e1o th\u1ee7 nh\u01b0 Patrick Vieira v\u00e0 Thierry Henry c\u0169ng \u0111\u01b0\u1ee3c \u0111\u01b0a v\u00e0o t\u1ea7m ng\u1eafm. Theo Mirror, Mikel Arteta c\u0169ng \u0111\u01b0\u1ee3c nh\u1eafm thay Wenger.</div>\r\n<div style=\"text-align: justify;\"><br>\r\nC\u1ea7u th\u1ee7 ng\u01b0\u1eddi T\u00e2y Ban Nha c\u00f3 5 n\u0103m ch\u01a1i b\u00f3ng cho Arsenal, hi\u1ec7n anh \u0111\u00e3 gi\u1ea3i ngh\u1ec7 v\u00e0 \u0111ang l\u00e0m tr\u1ee3 l\u00fd cho Pep Guardiola \u1edf Man City. C\u00f3 r\u1ea5t nhi\u1ec1u \u00fd ki\u1ebfn tr\u00e1i chi\u1ec1u v\u1ec1 vi\u1ec7c&nbsp; Arteta thay th\u1ebf Wenger.</div>\r\n<div style=\"text-align: justify;\"><br>\r\nM\u1ed9t s\u1ed1 ng\u01b0\u1eddi cho r\u1eb1ng v\u1edbi kinh nghi\u1ec7m \u0111\u00e3 t\u1eebng l\u00e0m vi\u1ec7c v\u1edbi Arsenal c\u1ef1u sao Everton s\u1ebd kh\u00f4ng m\u1ea5y kh\u00f3 kh\u0103n \u0111\u1ec3 h\u00f2a nh\u1eadp v\u1edbi Ph\u00e1o th\u1ee7, m\u1ed9t s\u1ed1 kh\u00e1c th\u00ec cho r\u1eb1ng Arteta ch\u01b0a \u0111\u1ee7 kinh nghi\u1ec7m \u0111\u1ec3 thay th\u1ebf \u00f4ng th\u1ea7y ng\u01b0\u1eddi Ph\u00e1p.</div>\r\n<div style=\"text-align: justify;\">&nbsp;</div>\r\n<h2>Ramsey n\u00f3i v\u1ec1 Arteta</h2>\r\n<h2>&nbsp;</h2>\r\n<div style=\"text-align: justify;\">Aaron Ramsey ph\u00e1t bi\u1ec3u v\u1ec1 Mikel Arteta, anh kh\u1eb3ng \u0111\u1ecbnh tr\u1ee3 l\u00fd do Pep Guardiola c\u00f3 th\u1ec3 tr\u1edf th\u00e0nh m\u1ed9t HLV gi\u1ecfi trong t\u01b0\u01a1ng lai.</div>\r\n<div style=\"text-align: justify;\">\r\n<div style=\"text-align: center; width: 100%\" class=\"imagecontainer\">\r\n<table style=\"text-align: center; width:100%;\">\r\n    <tbody>\r\n        <tr style=\"width:100%;\">\r\n            <td style=\"width: 100%;\" align=\"center\"><img style=\"border: none\" alt=\"tien ve Arteta\" title=\"tien ve Arteta\" src=\"https://static.bongda24h.vn/medias/mobile/2016/5/21/Arsenal-hinh-anh-8.jpg\"></td>\r\n        </tr>\r\n        <tr>\r\n            <td>\r\n            <h3>Ramsey tin Arteta s\u1ebd tr\u1edf th\u00e0nh HLV gi\u1ecfi trong t\u01b0\u01a1ng lai</h3>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n</div>\r\n&ldquo;Anh \u1ea5y l\u00e0 m\u1ed9t c\u1ea7u th\u1ee7 tuy\u1ec7t v\u1eddi, anh \u1ea5y l\u00e0 m\u1ed9t ng\u01b0\u1eddi \u0111\u1ed9i tr\u01b0\u1edfng m\u1eabu m\u1ef1c, m\u1ed9t ng\u01b0\u1eddi lu\u00f4n l\u00e0 \u0111i\u1ec3m t\u1ef1a cho c\u00e1c \u0111\u1ed3ng \u0111\u1ed9i. Arteta \u0111ang l\u00e0m vi\u1ec7c v\u1edbi&nbsp;Pep, anh \u1ea5y \u0111ang t\u00edch l\u0169y nh\u1eefng kinh nghi\u1ec7m \u0111\u1ec3 c\u00f3 th\u1ec3 tr\u1edf th\u00e0nh m\u1ed9t HLV t\u1ed1t&rdquo;.</div>\r\n<div style=\"text-align: justify;\"><br>\r\n&ldquo;\u1ede th\u1eddi \u0111i\u1ec3m hi\u1ec7n t\u1ea1i, anh \u1ea5y c\u00f3 th\u1ec3 m\u1edbi ch\u1ec9 \u0111ang h\u1ecdc vi\u1ec7c, nh\u01b0ng m\u1ed9t v\u00e0i n\u0103m n\u1eefa anh \u1ea5y s\u1ebd l\u00e0 m\u1ed9t trong nh\u1eefng HLV gi\u1ecfi, t\u00f4i tin v\u00e0o \u0111i\u1ec1u \u0111\u00f3. T\u00f4i kh\u00f4ng bi\u1ebft Arsenal c\u00f3 nh\u1eafm Arteta thay Wenger hay kh\u00f4ng, t\u00f4i kh\u00f4ng bi\u1ebft th\u00f4ng tin n\u00e0y&rdquo;.</div>\r\n<div style=\"text-align: justify;\"><br>\r\nRamsey c\u0169ng kh\u1eb3ng \u0111\u1ecbnh Arsenal s\u1ebd quy\u1ebft t\u00e2m v\u00f4 \u0111\u1ecbch Europa League \u0111\u1ec3 l\u00e0m qu\u00e0 chia tay Wenger: &ldquo;Ch\u00fang t\u00f4i ph\u1ea3i b\u1ecf nh\u1eefng c\u1ea3m x\u00fac c\u00e1 nh\u00e2n sang m\u1ed9t b\u00ean, \u0111\u1ed9i b\u00f3ng \u0111ang quy\u1ebft t\u00e2m v\u00f4 \u0111\u1ecbch Europa League \u0111\u1ec3 l\u00e0m qu\u00e0 chia tay \u00f4ng \u1ea5y&rdquo;.</div>\r\n<div style=\"text-align: justify;\"><br>\r\n&ldquo;T\u00f4i v\u00e0 c\u00e1c \u0111\u1ed3ng \u0111\u1ed9i \u0111ang t\u1eadp trung cho hai tr\u1eadn b\u00e1n k\u1ebft v\u1edbi Atletico, ch\u00fang t\u00f4i \u0111\u1ee7 kh\u1ea3 n\u0103ng \u0111\u1ec3 \u0111\u00e1nh b\u1ea1i h\u1ecd v\u00e0 ti\u1ebfn v\u00e0o chung k\u1ebft. Ch\u00fang t\u00f4i \u0111ang t\u1eadp trung ho\u00e0n to\u00e0n v\u00e0o hai tr\u1eadn \u0111\u1ea5u v\u1edbi Atletico&rdquo;.</div>\r\n<div style=\"text-align: justify;\"><br>\r\nL\u00ea H\u01b0\u1eddng (TTVN)&nbsp;&nbsp;</div>\r\n<div style=\"text-align: justify;\">&nbsp;</div></div></body></html>","new_url":"","id":"1659","checkdouble":"185061"},{"date":"18:33 26/04","title":"Roy Keane: \u201cSalah ch\u1ec9 ngang h\u00e0ng v\u1edbi Ronaldo v\u00e0 Messi n\u1ebfu\u2026\u201d","type":"B\u00f3ng \u0111\u00e1 Anh","img_url":"https://static.bongda24h.vn/medias/original/2018/4/20/roy-keane-salah-chi-ngang-hang-voi-ronaldo-va-messi-neu.jpg","new_desc":"<html><head><style type='text/css'>@font-face{font-family:MyWebFont;src:url(NotoSans-Regular.ttf);font-weight:400}@font-face{font-family:MyWebFont;src:url(NotoSans-Bold.ttf);font-weight:700}body{background:#fff;font-family:MyWebFont,Arial,Helvetica,sans-serif;font-size:12px;padding:0;margin:0}iframe a{margin:6px}.clear{clear:both}.clear5px{clear:both;height:10px}img{border:0}h1{margin:6px 0;font-size:24px;color:#f00}h2{color:#f00;float:left;font-size:16px;margin:0}.mnh2{color:#f00;float:left;font-size:16px;margin:0}h3{margin:0}h4{margin:0}div.adContainer video{left:0}.adContainer{position:absolute;left:0;top:0;z-index:2}.jp-video-full div.adContainer div{top:0;left:0}.closeAdsbt{position:absolute;z-index:1000;right:5px;bottom:80px;color:#fff;background-color:#0f0f0f;padding:5px;opacity:.5;cursor:pointer;border-radius:3px;font-weight:bold}.closeAds{position:absolute;z-index:1000;right:5px;bottom:80px;color:#fff;background-color:#0f0f0f;padding:5px;opacity:.5}.articlerelatepannel{padding:6px;margin-top:5px;margin-bottom:5px;background-color:#f7f7f7;border: